const body = $json.body || $json;
if (!body.provider || !body.input) throw new Error('provider + input required');
if (!body.input.scheduledAt) throw new Error('input.scheduledAt required (ISO 8601 future timestamp)');
const scheduled = new Date(body.input.scheduledAt);
if (Number.isNaN(scheduled.getTime())) throw new Error('input.scheduledAt is not a valid ISO timestamp');
if (scheduled.getTime() <= Date.now()) throw new Error('input.scheduledAt must be in the future');
return [{ json: {
  correlationId: `inv-sched-${Date.now()}-${Math.floor(Math.random()*1e6)}`,
  startedAt: new Date().toISOString(),
  provider: body.provider,
  input: body.input,
  scheduledAt: body.input.scheduledAt
}}];

const state = $('Stamp + validate scheduledAt').first().json;
const statusCode = Number($json.statusCode ?? 0);
const respBody = $json.body ?? $json;
const ok = statusCode >= 200 && statusCode < 300;
const unsupported = statusCode === 400 && respBody?.error?.code === 'UNSUPPORTED';
return [{ json: {
  ...state,
  statusCode,
  ok,
  unsupported,
  status: ok ? 'scheduled' : (unsupported ? 'unsupported-by-provider' : 'failed'),
  scheduledInvoiceRef: respBody?.result?.scheduledRef ?? null,
  errorCode: respBody?.error?.code ?? null,
  appliedAt: new Date().toISOString()
} }];
